import React, { useCallback, useRef, useState } from 'react';
import ReactFlow, {
  addEdge,
  Background,
  Connection,
  Controls,
  Edge,
  Node,
  OnConnect,
  ReactFlowProvider,
  ReactFlowInstance,
} from 'react-flow-renderer';
import './App.css';
import Sidebar from './Sidebar';
import CustomNode from './CustomNode';

const initialNodes: Node[] = [
  {
    id: '1',
    type: 'custom',
    data: { label: 'Cloud Provider (drag new nodes)', subtype: 'aws' },
    position: { x: 250, y: 5 },
  },
];

const initialEdges: Edge[] = [];

let id = 0;
const getId = () => `node_${id++}`;

function Flow() {
  const reactFlowWrapper = useRef<HTMLDivElement>(null);
  const [reactFlowInstance, setReactFlowInstance] = useState<ReactFlowInstance | null>(null);
  const [nodes, setNodes] = useState<Node[]>(initialNodes);
  const [edges, setEdges] = useState<Edge[]>(initialEdges);

  const onConnect: OnConnect = useCallback(
    (params: Connection) => setEdges((eds) => addEdge(params, eds)),
    []
  );

  const onDragOver = useCallback((event: React.DragEvent<HTMLDivElement>) => {
    event.preventDefault();
    event.dataTransfer.dropEffect = 'move';
  }, []);

  const onDrop = useCallback(
    (event: React.DragEvent<HTMLDivElement>) => {
      event.preventDefault();
      if (!reactFlowWrapper.current || !reactFlowInstance) return;

      const reactFlowBounds = reactFlowWrapper.current.getBoundingClientRect();
      const subtype = event.dataTransfer.getData('application/reactflow');
      if (!subtype) return;

      const position = reactFlowInstance.project({
        x: event.clientX - reactFlowBounds.left,
        y: event.clientY - reactFlowBounds.top,
      });

      const newNode: Node = {
        id: getId(),
        type: 'custom',
        position,
        data: { label: subtype.charAt(0).toUpperCase() + subtype.slice(1), subtype },
      };

      setNodes((nds) => nds.concat(newNode));
    },
    [reactFlowInstance]
  );

  const onDragStart = useCallback(
    (event: React.DragEvent<HTMLDivElement>, subtype: string) => {
      event.dataTransfer.setData('application/reactflow', subtype);
      event.dataTransfer.effectAllowed = 'move';
    },
    []
  );

  const nodeTypes = { custom: CustomNode };

  const [analysis, setAnalysis] = useState<any>(null);

  const runAnalysis = useCallback(() => {
    // gather current nodes/edges from state rather than requiring a flow instance
    const payload = { nodes, edges };

    fetch('/analyze', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    })
      .then((r) => r.json())
      .then(setAnalysis)
      .catch((err) => console.error('analysis error', err));
  }, [nodes, edges]);

  return (
    <div className="dndflow">
      <Sidebar onDragStart={onDragStart} />
      <div className="reactflow-wrapper" ref={reactFlowWrapper}>
        <div className="toolbar">
          <button onClick={runAnalysis}>Run Analysis</button>
        </div>
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onConnect={onConnect}
          onInit={setReactFlowInstance}
          onDrop={onDrop}
          onDragOver={onDragOver}
          nodeTypes={nodeTypes}
          fitView
        >
          <Background />
          <Controls />
        </ReactFlow>
        {analysis && (
          <div className="analysis-panel">
            <h3>Analysis Result</h3>
            <pre>{JSON.stringify(analysis, null, 2)}</pre>
          </div>
        )}
      </div>
    </div>
  );
}

function App() {
  return (
    <div className="App">
      <ReactFlowProvider>
        <Flow />
      </ReactFlowProvider>
    </div>
  );
}

export default App;
